class Solution:
    def longestConsecutive(self, nums: List[int]) -> int:
        od = defaultdict(int)
        for val in nums:
            od[val] = 0


        max_length = 0
        for key, val in od.items():
            if val == -1:
                continue

            temp_length = 1
            temp_val1 = key
            temp_val2 = key
            while temp_val1 + 1 in od:
                od[temp_val1 + 1] = -1
                temp_val1 += 1
                temp_length += 1

            while temp_val2 - 1 in od:
                od[temp_val2 - 1] = -1
                temp_val2 -= 1
                temp_length += 1


            max_length = max(max_length, temp_length)

        return max_length
